// Example PM2 process management script for a Node.js backend (ecosystem.config.js)
module.exports = {
  apps: [
    {
      name: 'backend-app',
      script: './dist/server.js',
      instances: 'max',
      exec_mode: 'cluster',
      env: {
        NODE_ENV: 'development',
        PORT: 3000,
      },
      watch: true,
      ignore_watch: ['node_modules', 'logs'],
      error_file: './logs/pm2-error.log',
      out_file: './logs/pm2-out.log',
      merge_logs: true,
    },
  ],
};

This script configures PM2 to manage a Node.js backend process in cluster mode, enabling hot-reloading, logging, and efficient resource utilization for debugging.
